import{_ as r,o as n,c as i,ag as t}from"./chunks/framework.DXGyWiRo.js";const p="/images/uebung014.jpg",s="/images/uebung016.jpg",m=JSON.parse('{"title":"Übung Lektion 15","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung15.md","filePath":"lektionen/uebung15.md"}'),a={name:"lektionen/uebung15.md"};function d(u,e,l,h,c,g){return n(),i("div",null,[...e[0]||(e[0]=[t('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-15" tabindex="-1">Übung Lektion 15 <a class="header-anchor" href="#ubung-lektion-15" aria-label="Permalink to &quot;Übung Lektion 15&quot;">​</a></h1><p>A) Übersetzen Sie das Sprichwort zu Beginn der Lektion</p><p>गुरुशुश्रूषया विद्या<br> पुष्कलेन धनेन वा ।<br> अथवा विद्यया विद्या<br> चतुर्थी नैव विद्यते ॥</p><p>Wissen gibt es durch Gehorsam gegenüber einem Lehrer oder für üppig viel Geld oder im Austausch gegen Wissen. Eine vierte Möglichkeit gibt es nicht.</p><p>B) Lösen Sie folgende Tatpuruṣa auf:</p><p>१. बलकृतः । बलेन कृतः ein gewalttätiger</p><p>२. बालधनस्य । बालस्य धनस्य des Eigentums eines Minderjährigen</p><p>३. नरकाकम् । काक इव नरम् । नर एव काकम् einen Mann wie eine Krähe</p><p>४. लोकगुरोः । लोकस्य गुरोः । लोकानां गुरोः des Meisters / Lehrers der Leute / der Welt / der Welten</p><p>५. जलेश्वरेण । जलस्येश्वरेण । जालानामीश्वरेण durch den HERRN der Wasser = durch Varuṇa</p><p>६. जनपानम् । जनस्य पानम् । जनानां पानम् Trank für die Leute / für die Menschen</p><p>७. वाक्यसारथीन् । वाक्यस्य सारथीन् । वाक्यानां सारथीन् die (Akk.) Wortführer</p><p>८. गुणवचनानि । गुणस्य वचनानि । गुणानां वचनानि Eigenschaftswörter</p><p>९. मृगेश्वरैः । मृगस्येश्वरैः । मृगाणामीश्वरैः durch die HERREN der Wildtiere = durch Löwen</p><p>१०. बुद्धिकृतायाः । बुद्ध्या कृतायाः der (Gen.), die mit Vernunft gemacht wurde, vernünftig gehandelt</p><p>११. धर्मयज्ञेन । धर्मेनैव यज्ञेन । धर्मस्य यज्ञ्नेन durch ein unblutiges Opfer</p><p>१२. यज्ञाङ्गानि । यज्ञस्याङ्गानि । यज्ञानामङ्गानि Gliieder / Bestandteile / Teile eine Opfers, Opfergeräte</p><p>१३. गृहजनेन । गृहस्य जनेन durch die Familie</p><p>१४. ग्रामलेखकाः । ग्रामाणां लेखकाः die Dorfschreiber</p><p>१५. नागदेवः । नागानां देवः Schlangengott, Schlangenfürst, Elefantengott, Elefantenkönig</p><p>१६. पुण्यजिताभिः । पुण्येन जिताभिः durch durch Verdienst / Gutestun ersiegte (fem.)</p><p>१७. पापलोकम् । पापस्य लोकम् । पापानां लोकम् । पापं लोकम् die (Akk.) Welt des Bösen, Welt der Bösen, Hölle, böse Welt</p><p>१८. सत्यवदनस्य । सत्यस्य वदनस्य des Sprechens der Wahrheit</p><p>१९. दानधर्मेण । दानस्य धर्मेण । दानेनैव धर्मेण durch die Pflicht zu Spenden</p><p>२०. सुखप्रश्नः । सुखस्य प्रश्नः । सुखः प्रश्नः Frage nach dem Glück, Frage nach dem Wohlsein, Frage nach dem Befinden, eine leichte Frage</p><p>२१. दुःखमोहस्य । दुःखस्य मोहस्य । दुःखेन मोहस्य der Verwirrung durch das Leid, Verzweiflung, Verblendung bezüglich des Leides</p><p>२२. सोमपात्राणि ।  सोमस्य पात्राणि Somagefäße</p><p>२३. स्वर्गमार्गः । स्वर्गस्य मार्गः । स्वर्गं मार्गः Weg zum Himmel</p><p>२४. कामधेन्वा । कामस्य धेन्वा । कामानां धेन्वा durch die Wunschkuh</p><p>२५. वर्णधर्मः । वर्णानां धर्मः Ständerecht</p><p>२६. श्रुत्युदितम् । श्रुत्योदितम् । श्रुतेरुदितम् vom Veda Gesagtes / Vorgeschriebenes</p><p><img src="'+p+'" alt=""><br> Abb.: जलेश्वरो वरुणः<br> Bundi (बुन्दी), Rajasthan (राजस्थान), um 1675-1700<br> [Bildquelle: Wikipedia. Public domain]</p><p>Lösung zu den <a href="./uebung16">Übungen 16 - 20</a></p><p>Lösen Sie folgende Komposita als Tatpuruṣa in Sanskrit auf und geben Sie eine deutsche Übersetzung. Geben Sie jeweils alle Auflösungen und Übersetzungen, die Ihnen möglich erscheinen. Geben Sie auch an, um welchen Kasus und welche Zahl es sich beim Gesamtkompositum handelt.</p><p>१. देवेन्द्रस्य । देवानामिन्द्रस्य Des Götterfürsten</p><p>२. दुःखदग्धा । दुःखेन दग्धा eine von Leid verbrannte Frau</p><p>३. मोक्षधर्मः । मोक्षस्य धर्मः die Lehre von der Erlösung, das Gesetz der Erlösung</p><p>४. अन्नजातानि । अन्नेन जातानि । अन्नस्य जातानि von Speise Hervorgebrachtes, Arten des Essens</p><p>५. गृहकरणम् । गृहस्य करणम् Hausarbeit</p><p>६. शूद्रकृतेन । शूद्रस्य कृतेन । शूद्राणां कृतेन durch Śūdrawerk</p><p>७. ईश्वरपूजा । ईश्वरस्य पूजा Gottesdienst</p><p>८. देवेश्वरः । देवानामीश्वरः HERR der Götter</p><p>९. क्षत्रिययज्ञम् । क्षत्रियस्य यज्ञम् । क्षत्रियाणां यज्ञम् Opfer (Akkusativ) der Kaṣatriyas / des Kṣatriya, Opfer für Kṣatriyas / einen Kṣatriya</p><p>१०. वैश्यभावेन । वैश्यस्य भावेन । वैश्यानां भावेन durch Vaiśyawesen</p><p>११. देवगुरोः । देवानां गुरोः । देवस्येव् गुरोः । देवस्यैव गोरोः des Götterlehrers, des göttergleichen Lehrers, des göttlichen Lehrers</p><p>१२. धनलोभः॥ धनस्य लोभः । धनानां लोभः materieller Gewinn</p><p>१३. गृहदासी । गृहस्य दासी Hausmagd</p><p>१४. दुःखमोहः । दुःखस्य मोहः Verblendung über das Leiden, Verwirrung durch Leiden</p><p>१५. ग्रामेश्वरम्  । ग्रामस्येश्वरम् । ग्रामाणामीश्वरम् der Dorfherren</p><p>१६. नगरजनाः । नगरस्य जनाः । नगराणां जनाः Stadtvolk, Städter</p><p>१७. यज्ञकालस्य॥ यज्ञस्य कालस्य । जज्ञानां कालस्य des rechten Zeitpunkts für das Opfer / für Opfer, der Zeit ...</p><p>१८. देवगृहाणि । देवस्य गृहाणि । देवाणां गृहाणि Gotteshäuser</p><p>१९. देवपुत्राणाम् । देवानां पुत्राणाम् der Göttersöhne</p><p>२०. पश्विष्टिः । पशोरिष्टिः । पशूनामीष्टिः Tieropfer</p><p>२१. स्मृत्युक्तम् । स्मृत्योक्तम् । स्मृतेरुक्तम् । स्मृत्या उक्तम् Spruch der heiligen Überlieferung</p><p>२२. गुरुगृहम् । गुरोर्गृहम् । गुरूणां गृहम् Haus des Meisters / der Meister</p><p>२३. सोमयज्ञेन । सोमस्य यज्ञेन durch ein Somaopfer</p><p>२४. स्वर्गगताः । स्वर्गं गताः in den Himmel Gekommene</p><p>२५. सुखप्रश्नम् । सुखस्य प्रश्नम्  सुखं प्रश्नम् die (Akk.) Frage nach dem Glück, Frage nach dem Wohlergehen, Frage nach der Befindlichkeit, leichte Frage</p><p>२६. पशुधर्मः । पशोर्धर्मः । पशूनां धर्मः das Gesetz des Viehs, viehisches Verhalten</p><p>२७. स्वर्गलोकः । स्वर्गाणां लोकः । स्वर्ग एव लोकः Himmelswelt, Welt der Himmel</p><p>२८. ऋषियज्ञैः । ऋषेर्यज्ञैः । ऋषीणां यज्ञैः durch Opfer vedischer Weiser / des vedischen Weisen</p><p>२९. तत्कालम् । तस्य कालम् । त्स्याः कालम् । तेषां कालम् । तासां कालं Zeit (Akkusativ) dafür, der (rechte) Zeitpunkt dafür</p><p>३०. सत्यवदनम् । स्त्यस्य वदनम् Wahrheitsrede, Sprechen der Wahrheit</p><p><img src="'+s+'" alt=""><br> Abb.: गृहकरणम्<br> Kerala (കേരളം)<br> [Bildquelle: sallylondon. -- <a href="http://www.flickr.com/photos/sallylondon/141012470/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/sallylondon/141012470/</a>. -- Zugriff am 2008-12-06. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p>',66)])])}const f=r(a,[["render",d]]);export{m as __pageData,f as default};
